        // `append(true)` opens the file with `FILE_APPEND_DATA` access,
        // which is a restricted write subset insufficient for
        // `LockFileEx`'s exclusive lock, causing "Access is denied"
        // (os error 5).  Full `read+write` access satisfies LockFileEx on
        // all platforms.  We reproduce append semantics by seeking to the
        // end of the file while holding the exclusive lock.
        let file = OpenOptions::new()
            .create(true)
            .read(true)
            .write(true)
            .open(&path)?;
        let mut lock = RwLock::new(file);

        // Retry with exponential backoff to handle transient OS-level file
        // lock races (particularly on Windows where background file-system
        // activity can cause brief lock denial).
