                        std::thread::sleep(std::time::Duration::from_millis(
                            10u64 << attempt,
                        ));
                    } else {
                        last_err = Some(e);
                    }
                }
            }
        }

        Err(Error::lock_failed(
            last_err.map_or_else(|| "unknown error".to_string(), |e| e.to_string()),
        ))
    })
    .await??;

    Ok(())
