/// or corrupt the file.  This exercises the read+write open mode and the
/// retry-on-lock-failure logic added to fix the Windows "Access is denied"
/// (os error 5) bug (see GitHub issue #434).
#[tokio::test(flavor = "multi_thread", worker_threads = 4)]
async fn test_concurrent_appends_are_all_persisted() {
    use std::sync::Arc;

    let (store, _dir) = temp_store();
    let store = Arc::new(store);
    const N: usize = 20;

    let handles: Vec<_> = (0..N)
        .map(|i| {
            let store = Arc::clone(&store);
            tokio::spawn(async move {
                store
                    .append("concurrent", &json!({"i": i}))
                    .await
                    .unwrap();
            })
        })
        .collect();

    for h in handles {
        h.await.unwrap();
    }

    let msgs = store.read("concurrent").await.unwrap();
    assert_eq!(
        msgs.len(),
        N,
        "all {N} concurrent appends should be persisted, got {}",
        msgs.len()
    );
}

